const body = $json.body ?? $json;
const question = String(body.question ?? body.message ?? '').trim();
if (!question) throw new Error('question is required');
const sessionId = String(body.session_id ?? body.user_id ?? 'default').trim();
const userId = String(body.user_id ?? 'anonymous').trim();
const token = $env.AGENT_WORKFLOW_TOKEN || '';
const traceId = String(body.trace_id ?? `${sessionId}-${Date.now()}`).trim();
return [{
  json: {
    session_id: sessionId,
    user_id: userId,
    question,
    token,
    trace_id: traceId
  }
}];

const normalized = $node['Normalize Input'].json;
const question = String(normalized.question ?? '').trim();
const questionLower = question.toLowerCase().replace(/ё/g, 'е');
const normalizedQuestion = questionLower
  .replace(/[^\p{L}\p{N}\s-]+/gu, ' ')
  .replace(/докера/g, 'docker')
  .replace(/докер/g, 'docker')
  .replace(/контенер/g, 'контейнер')
  .replace(/[_-]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const stopWords = new Set([
  'что', 'это', 'как', 'для', 'или', 'про', 'над', 'под', 'такое', 'такой',
  'какая', 'какое', 'кто', 'зачем', 'почему', 'расскажи', 'объясни',
  'the', 'and', 'with', 'from', 'into', 'about', 'vs'
]);
const terms = normalizedQuestion
  .split(' ')
  .map((term) => term.trim())
  .filter((term) => term.length >= 2 && !stopWords.has(term))
  .slice(0, 16);
const fallbackTerms = normalizedQuestion
  .split(' ')
  .map((term) => term.trim())
  .filter((term) => term.length >= 3)
  .slice(0, 10);
const searchTerms = terms.length > 0 ? terms : fallbackTerms;
const questionPlain = normalizedQuestion || questionLower;
const tsText = searchTerms.length > 0 ? searchTerms.join(' ') : questionPlain;
const questionPlainSql = questionPlain.replace(/'/g, "''");
const questionTermsSql = searchTerms.join(' ').replace(/'/g, "''");
const questionTsSql = tsText.replace(/'/g, "''");
const limitRaw = Number($env.AGENT_WIKI_LIMIT ?? 5);
const limit = Number.isFinite(limitRaw) ? Math.max(1, Math.min(20, Math.trunc(limitRaw))) : 5;
const maxContextCharsRaw = Number($env.AGENT_WIKI_CONTEXT_CHARS ?? 8000);
const maxContextChars = Number.isFinite(maxContextCharsRaw) ? Math.max(1000, Math.min(50000, Math.trunc(maxContextCharsRaw))) : 8000;
const identRe = /^[A-Za-z_][A-Za-z0-9_]{0,62}$/;
const wikiSchema = String($env.AGENT_WIKI_SCHEMA || 'public').trim();
const wikiTable = String($env.AGENT_WIKI_TABLE || 'pages').trim();
const wikiTitleColumn = String($env.AGENT_WIKI_TITLE_COLUMN || 'title').trim();
const wikiPathColumn = String($env.AGENT_WIKI_PATH_COLUMN || 'path').trim();
const wikiContentColumn = String($env.AGENT_WIKI_CONTENT_COLUMN || 'content').trim();
for (const [name, value] of Object.entries({ wikiSchema, wikiTable, wikiTitleColumn, wikiPathColumn, wikiContentColumn })) {
  if (!identRe.test(value)) {
    throw new Error('invalid ' + name);
  }
}
return [{
  json: {
    ...normalized,
    question_plain_sql: questionPlainSql,
    question_terms_sql: questionTermsSql,
    question_ts_sql: questionTsSql,
    question_terms_count: searchTerms.length,
    limit,
    max_context_chars: maxContextChars,
    wiki_schema_sql: wikiSchema,
    wiki_table_sql: wikiTable,
    wiki_title_column_sql: wikiTitleColumn,
    wiki_path_column_sql: wikiPathColumn,
    wiki_content_column_sql: wikiContentColumn
  }
}];

const maxChars = Number($node['Build Wiki Query'].json.max_context_chars ?? 8000);
const rows = items.map((item) => item.json);
let used = 0;
let topScore = 0;
let topTermHits = 0;
const blocks = [];
const sources = [];
for (const row of rows) {
  const title = String(row.title ?? '').trim();
  const path = String(row.path ?? '').trim();
  const content = String(row.content ?? '').replace(/\s+/g, ' ').trim();
  const score = Number(row.score ?? 0);
  const termHits = Number(row.term_hits ?? 0);
  if (Number.isFinite(score) && score > topScore) topScore = score;
  if (Number.isFinite(termHits) && termHits > topTermHits) topTermHits = termHits;
  if (!content) continue;
  const snippet = content.length > 1600 ? `${content.slice(0, 1600)}…` : content;
  const docId = `D${sources.length + 1}`;
  sources.push({ id: docId, title, path, content: snippet, score, term_hits: termHits });
  const block = [
    `[${docId}]`,
    title ? `TITLE: ${title}` : null,
    path ? `PATH: ${path}` : null,
    `CONTENT: ${snippet}`
  ].filter(Boolean).join('\n');
  const nextUsed = used + block.length + (blocks.length > 0 ? 6 : 0);
  if (nextUsed > maxChars && blocks.length > 0) break;
  blocks.push(block);
  used = nextUsed;
}
const contextText = blocks.join('\n\n---\n\n');
return [{
  json: {
    count: blocks.length,
    memory_text: contextText,
    context_source: 'wiki',
    top_score: topScore,
    top_term_hits: topTermHits,
    sources
  }
}];

const normalized = $node['Normalize Input'].json;
const queryMeta = $node['Build Wiki Query'].json;
const memory = String($json.memory_text ?? '').trim();
const memoryCount = Number($json.count ?? 0);
const topScore = Number($json.top_score ?? 0);
const topTermHits = Number($json.top_term_hits ?? 0);
const questionTermsCount = Number(queryMeta.question_terms_count ?? 0);
const sources = Array.isArray($json.sources) ? $json.sources : [];
const minMemoryCharsRaw = Number($env.AGENT_MIN_MEMORY_CHARS ?? 40);
const minMemoryChars = Number.isFinite(minMemoryCharsRaw) ? Math.max(0, Math.trunc(minMemoryCharsRaw)) : 40;
const minWikiScoreRaw = Number($env.AGENT_WIKI_MIN_SCORE ?? 2);
const minWikiScore = Number.isFinite(minWikiScoreRaw) ? Math.max(0, minWikiScoreRaw) : 2;
const minTermHitsRaw = Number($env.AGENT_WIKI_MIN_TERM_HITS ?? 1);
const minTermHits = Number.isFinite(minTermHitsRaw) ? Math.max(0, minTermHitsRaw) : 1;
const memoryHasContext = memoryCount > 0 && memory.length >= minMemoryChars && topScore >= minWikiScore && topTermHits >= minTermHits;
const questionLower = String(normalized.question ?? '').toLowerCase().replace(/ё/g, 'е');
const greetingPatterns = [/^привет\b/, /^здравствуй/, /^добрый\s+(день|вечер|утро)\b/, /^hello\b/, /^hi\b/];
const isGreetingQuestion = greetingPatterns.some((re) => re.test(questionLower));
const identityPatterns = [/кто\s+ты/, /ты\s+кто/, /who\s+are\s+you/];
const isIdentityQuestion = identityPatterns.some((re) => re.test(questionLower));
const identityAnswer = 'Я внутренний ИИ ассистент.';
const greetingAnswer = 'Привет! Я внутренний ИИ ассистент.';
const metaQuestionPatterns = [
  /твоя роль/,
  /системн(ый|ого)? промпт/,
  /инструкц/,
  /что ты умеешь/,
  /чувств/,
  /памят[ьи]/,
  /session/
];
const isMetaQuestion = metaQuestionPatterns.some((re) => re.test(questionLower));
const defaultSystemPrompt = [
  'Ты внутренний инфраструктурный ассистент.',
  'Всегда отвечай на русском языке.',
  'Отвечай только на основании источников из CONTEXT.',
  'Нельзя добавлять факты, которых нет в источниках.',
  'Верни строго JSON без markdown и без дополнительного текста.',
  'Формат: {"answer":"...","citations":["D1"],"enough_context":true}',
  'Если данных недостаточно: {"answer":"Нет данных.","citations":[],"enough_context":false}'
].join(' ');
const systemPrompt = String($env.AGENT_SYSTEM_PROMPT || defaultSystemPrompt).trim();
const ollamaModel = String($env.OLLAMA_MODEL || '').trim();
if (!ollamaModel) throw new Error('OLLAMA_MODEL is required');
const prompt = [
  systemPrompt,
  '',
  'CONTEXT:',
  memoryHasContext ? memory : '[empty]',
  '',
  'SOURCES_JSON:',
  JSON.stringify(sources),
  '',
  `QUESTION: ${normalized.question}`,
  '',
  'Ответ верни только JSON-объектом.'
].join('\n');
return [{
  json: {
    session_id: normalized.session_id,
    user_id: normalized.user_id,
    question: normalized.question,
    token: normalized.token,
    trace_id: normalized.trace_id,
    memory_count: memoryCount,
    memory_has_context: memoryHasContext,
    top_score: topScore,
    top_term_hits: topTermHits,
    question_terms_count: questionTermsCount,
    min_wiki_score: minWikiScore,
    min_term_hits: minTermHits,
    is_identity_question: isIdentityQuestion,
    is_greeting_question: isGreetingQuestion,
    identity_answer: identityAnswer,
    greeting_answer: greetingAnswer,
    is_meta_question: isMetaQuestion,
    ollama_model: ollamaModel,
    prompt,
    sources
  }
}];

const base = $node['Build Prompt'].json;
const allowGeneralKb = String($env.AGENT_ALLOW_GENERAL_KB || 'false').toLowerCase() === 'true';
const minOverlapRaw = Number($env.AGENT_MIN_ANSWER_OVERLAP ?? 0);
const minOverlap = Number.isFinite(minOverlapRaw) ? Math.max(0, Math.trunc(minOverlapRaw)) : 0;
let answer = 'Нет данных.';
let guardReason = 'ok';
let citations = [];
let overlapCount = 0;
if (base.is_greeting_question) {
  answer = String(base.greeting_answer || 'Привет! Я внутренний ИИ ассистент.');
  guardReason = 'greeting_fixed';
} else if (base.is_identity_question) {
  answer = String(base.identity_answer || 'Я внутренний ИИ ассистент.');
  guardReason = 'identity_fixed';
} else if (!allowGeneralKb && base.is_meta_question) {
  answer = 'Нет данных.';
  guardReason = 'meta_question_blocked';
} else if (!allowGeneralKb && !base.memory_has_context) {
  answer = 'Нет данных.';
  guardReason = 'no_context';
} else {
  const raw = String($json.response ?? '').trim();
  const tryParseJson = (input) => {
    if (!input) return null;
    try {
      return JSON.parse(input);
    } catch {
      return null;
    }
  };
  const extractJsonObject = (input) => {
    if (!input) return '';
    const cleaned = input
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/i, '')
      .trim();
    if (!cleaned) return '';
    let depth = 0;
    let start = -1;
    let inString = false;
    let escaped = false;
    for (let i = 0; i < cleaned.length; i += 1) {
      const ch = cleaned[i];
      if (inString) {
        if (escaped) {
          escaped = false;
        } else if (ch === '\\') {
          escaped = true;
        } else if (ch === '"') {
          inString = false;
        }
        continue;
      }
      if (ch === '"') {
        inString = true;
        continue;
      }
      if (ch === '{') {
        if (depth === 0) start = i;
        depth += 1;
      } else if (ch === '}') {
        if (depth > 0) depth -= 1;
        if (depth === 0 && start !== -1) {
          return cleaned.slice(start, i + 1);
        }
      }
    }
    return '';
  };
  let parsed = tryParseJson(raw);
  if (!parsed || typeof parsed !== 'object') {
    const extracted = extractJsonObject(raw);
    parsed = tryParseJson(extracted);
  }
  if (!parsed || typeof parsed !== 'object') {
    answer = 'Нет данных.';
    guardReason = 'model_non_json';
  } else {
    const parsedAnswer = String(parsed.answer ?? '').trim();
    const enoughContext = Boolean(parsed.enough_context);
    let parsedCitations = Array.isArray(parsed.citations)
      ? parsed.citations.map((v) => String(v || '').trim()).filter(Boolean)
      : [];
    if (!enoughContext || !parsedAnswer || parsedAnswer === 'Нет данных.') {
      answer = 'Нет данных.';
      guardReason = 'insufficient_context';
    } else {
      const sourceList = Array.isArray(base.sources) ? base.sources : [];
      const sourceMap = new Map(sourceList.map((s) => [String(s.id), String(s.content ?? '').toLowerCase()]));
      if (parsedCitations.length === 0 && sourceList.length > 0) {
        parsedCitations = [String(sourceList[0].id)];
      }
      const allValidCitations = parsedCitations.length > 0 && parsedCitations.every((id) => sourceMap.has(id));
      if (!allValidCitations) {
        answer = 'Нет данных.';
        guardReason = 'invalid_citations';
      } else {
        const citedText = parsedCitations.map((id) => sourceMap.get(id) || '').join(' ');
        const tokenSet = new Set(
          parsedAnswer
            .toLowerCase()
            .replace(/[^\p{L}\p{N}\s-]+/gu, ' ')
            .split(/\s+/)
            .map((t) => t.trim())
            .filter((t) => t.length >= 4)
        );
        overlapCount = 0;
        for (const token of tokenSet) {
          if (citedText.includes(token)) overlapCount += 1;
        }
        if (minOverlap > 0 && overlapCount < minOverlap) {
          answer = 'Нет данных.';
          guardReason = 'evidence_mismatch';
        } else {
          answer = parsedAnswer;
          citations = parsedCitations;
          guardReason = 'ok';
        }
      }
    }
  }
}
const shouldPersistAssistant = answer !== 'Нет данных.' && (guardReason === 'ok' || guardReason === 'identity_fixed' || guardReason === 'greeting_fixed');
return [{
  json: {
    session_id: base.session_id,
    user_id: base.user_id,
    question: base.question,
    answer,
    citations,
    token: base.token,
    trace_id: base.trace_id,
    memory_count: base.memory_count,
    memory_has_context: base.memory_has_context,
    top_score: base.top_score,
    top_term_hits: base.top_term_hits,
    question_terms_count: base.question_terms_count,
    min_wiki_score: base.min_wiki_score,
    min_term_hits: base.min_term_hits,
    is_identity_question: base.is_identity_question,
    is_greeting_question: base.is_greeting_question,
    is_meta_question: base.is_meta_question,
    ollama_model: base.ollama_model,
    guard_reason: guardReason,
    overlap_count: overlapCount,
    should_persist_assistant: shouldPersistAssistant,
    prompt: base.prompt
  }
}];

const base = $node['Normalize Answer'].json;
const debugEnabled = String($env.AGENT_DEBUG || 'false').toLowerCase() === 'true';
const response = {
  ok: true,
  trace_id: base.trace_id,
  session_id: base.session_id,
  user_id: base.user_id,
  question: base.question,
  answer: base.answer,
  citations: Array.isArray(base.citations) ? base.citations : []
};
if (debugEnabled) {
  response.debug = {
    memory_count: Number(base.memory_count ?? 0),
    memory_has_context: Boolean(base.memory_has_context),
    top_score: Number(base.top_score ?? 0),
    top_term_hits: Number(base.top_term_hits ?? 0),
    question_terms_count: Number(base.question_terms_count ?? 0),
    min_wiki_score: Number(base.min_wiki_score ?? 0),
    min_term_hits: Number(base.min_term_hits ?? 0),
    is_identity_question: Boolean(base.is_identity_question),
    is_meta_question: Boolean(base.is_meta_question),
    guard_reason: String(base.guard_reason ?? 'unknown'),
    overlap_count: Number(base.overlap_count ?? 0),
    prompt_preview: String(base.prompt ?? '').slice(0, 600)
  };
}
return [{ json: response }];
